(979, 'xoo-plugin-info-side-cart-woocommerce', 'a:12:{s:4:\"name\";s:29:\"Woocommerce Side Cart Premium\";s:4:\"slug\";s:21:\"side-cart-woocommerce\";s:6:\"author\";s:39:\"<a href=\"https://xootix.com\">XootiX</a>\";s:14:\"author_profile\";s:36:\"http://profiles.wordpress.org/xootix\";s:7:\"version\";s:5:\"4.5.3\";s:12:\"download_url\";s:90:\"https://xootix.com/wp-content/uploads/2025/04/woocommerce-side-cart-premium-cczw-4.5.3.zip\";s:8:\"requires\";s:3:\"3.0\";s:6:\"tested\";s:3:\"6.8\";s:12:\"requires_php\";s:3:\"5.3\";s:12:\"last_updated\";s:0:\"\";s:8:\"sections\";a:3:{s:11:\"description\";s:66:\"Manage your cart from just a click away with an interactive design\";s:12:\"installation\";s:40:\"Click the activate button and that\'s it.\";s:9:\"changelog\";s:1244:\"== 4.5.3 == 19-04-2025<br>\nLicense files update <br>\n<br>\n\n== 4.5.2 == 30-03-2025<br>\n* Improve - Login/Signup slider takes to checkout page on login<br>\n* Fix - jQuery deprecated error<br>\n* Fix - Basket shortcode color style option not working.<br>\n<br>\n\n== 4.5.1 == 15-03-2025<br>\n* Fix - Divi theme not accepting wp_body_open hook<br>\n<br>\n== 4.5 == 11-03-2025 <br>\n* Fix - Auto open cart not working when ajax disabled<br>\n<br>\n== 4.4.9<br>\n* added compatibility for themes missing wp_body_open hook<br>\n<br>\n\n== 4.4.8 ==<br>\n* Core files update<br>\n<br>\n\n== 4.4.7 ==<br>\n* Fix - Card layout - free gift layout<br>\n<br>\n\n== 4.4.6 ==<br><br>\n* Fix - favicon not working<br>\n* New - Card layout updates live in customizer<br>\n<br>\n\n== 4.4.5 ==<br>\n* License files<br>\n<br>\n\n== 4.4.4 ==<br>\n* Fix - Side cart not hiding on elementor pages.<br>\n<br>\n\n== 4.4.3 ==<br>\n* New - Google Pay payment button<br>\n<br>\n\n== 4.4.2 ==<br>\n* Fix - Decimal quantity update<br>\n<br>\n== 4.4.1 ==<br>\n* Fix - Deprecated warning<br>\n* Fix - Elementor keeps opening up on edit page<br>\n<br>\n\n== 4.4 ==<br>\n* New - Confetti celebration for checkpoints<br>\n* Fix - WPML translations not working<br>\n* Fix - WP Rocket<br>\n<br>\n\n== 4.3 ==\n* New - Auto update plugin \";}s:7:\"banners\";a:2:{s:3:\"low\";s:56:\"https://xootix.com/wp-content/uploads/2024/09/banner.jpg\";s:4:\"high\";s:0:\"\";}}', 'auto'),
